import { ConvertibleTarget } from './types';
import { units as temperature } from '../util-units/temperature';
export type TemperatureUnit = typeof temperature.kelvin | typeof temperature.degree_celsius | typeof temperature.degree_fahrenheit;
/**
 * Converts temperatures between Kelvin, Celsius, and Fahrenheit scales.
 *
 * @param input - The temperature value to convert
 * @param from - Source temperature unit (kelvin, degree_celsius, degree_fahrenheit)
 * @param to - Target temperature unit for conversion
 * @returns Converted temperature value
 *
 * @example
 * // Convert Celsius to Fahrenheit
 * convertTemperature(0, units.temperature.degree_celsius, units.temperature.degree_fahrenheit)
 * // Returns: 32
 *
 * @example
 * // Convert Fahrenheit to Kelvin
 * convertTemperature(68, units.temperature.degree_fahrenheit, units.temperature.kelvin)
 * // Returns: 293.15
 *
 * @example
 * // Convert Kelvin to Celsius
 * convertTemperature(273.15, units.temperature.kelvin, units.temperature.degree_celsius)
 * // Returns: 0
 */
export declare function convertTemperature<FromUnit extends TemperatureUnit, ToUnit extends TemperatureUnit>(input: number, from: FromUnit, to: ConvertibleTarget<FromUnit, ToUnit>): number;
